const json = $input.item.json;


let cvText = '';

if (typeof json.content === 'string' && json.content.trim().length > 20) {
  cvText = json.content.trim();
}

else if (typeof json.response === 'string' && json.response.trim().length > 20) {
  cvText = json.response.trim();
}

else if (typeof json.message === 'string' && json.message.trim().length > 20) {
  cvText = json.message.trim();
}

else if (json.choices && Array.isArray(json.choices) && json.choices[0]?.message?.content) {
  cvText = json.choices[0].message.content.trim();
}

else if (typeof json.output === 'string' && json.output.trim().length > 20 && json.output !== json.text) {
  cvText = json.output.trim();
}

else {
  const skip = ['text', 'binaryProperty', 'model', 'id', 'object', 'system_fingerprint'];
  for (const key of Object.keys(json)) {
    if (skip.includes(key)) continue;
    const val = json[key];
    if (typeof val === 'string' && val.trim().length > 100) {
      cvText = val.trim();
      break;
    }
  }
}


const formData = $('Application Form3').item.json;
const positionApplied = formData['Position Applied'] || 'Fullstack Developer';


const isValid = cvText.length > 50;

return {
  json: {
    cvText: cvText,
    positionApplied: positionApplied,
    cvLength: cvText.length,
    cvValid: isValid
  }
};

