    "yearsOfExperience": {
      "type": "number",
      "description": "Total years of relevant professional experience detected in the CV"
    },
    "fieldRelevance": {
      "type": "string",
      "description": "The candidate primary professional field relevance. One of: RELEVANT_DIRECT, RELEVANT_ADJACENT, IRRELEVANT"
    },
    "scoreCeiling": {
      "type": "integer",
      "description": "Maximum possible score based on field relevance. RELEVANT_DIRECT=10, RELEVANT_ADJACENT=6, IRRELEVANT=2"
    },
    "requirementScores": {
      "type": "object",
      "description": "Individual scores for each of the requirements. Keys are r1 through r8, values are numbers (0, 0.5, or the max weight for that requirement)."
    },
    "rawScore": {
      "type": "number",
      "description": "Sum of all requirement scores before ceiling is applied"
    },
    "qualificationRate": {
      "type": "integer",
      "description": "Final score: min(scoreCeiling, round(rawScore)). Integer 0-10."
    },
    "ratingDisplay": {
      "type": "string",
      "description": "Human-readable rating, e.g. 3/10, 7/10"
    },
    "category": {
      "type": "string",
      "description": "QUALIFIED if finalScore >= 7, REVIEW if 4-6, NOT_QUALIFIED if <= 3"
    },
    "explanation": {
      "type": "string",
      "description": "Point-by-point analysis. For each requirement: state STRONG_MET, PARTIAL, or MISSING with exact evidence quoted from CV."
    },
    "keyFindings": {
      "type": "string",
      "description": "Summary: field relevance assessment, experience level (Junior/Senior), ceiling applied, strongest qualifications, critical gaps, and final hiring recommendation."
    }
  },
  "required": [
    "positionApplied",
    "experienceLevel",
    "yearsOfExperience",
    "fieldRelevance",
    "scoreCeiling",
    "requirementScores",
    "rawScore",
    "qualificationRate",
    "ratingDisplay",
    "category",
    "explanation",
    "keyFindings"
  ],
  "additionalProperties": false
}

parameters.jsCode:
// Get original form data from Application Form trigger
const formData = $('Application Form3').item.json;

// Get AI output from the chain (previous node)
const aiOutput = $input.item.json;

// ============ ROBUST OUTPUT PARSING ============
let parsed = null;

if (aiOutput.output && typeof aiOutput.output === 'object' && aiOutput.output.qualificationRate !== undefined) {
  parsed = aiOutput.output;
} else if (typeof aiOutput.output === 'string') {
  try {
    parsed = JSON.parse(aiOutput.output);
  } catch(e) {
    const txt = aiOutput.output;
    const si = txt.indexOf('{');
    const ei = txt.lastIndexOf('}');
    if (si !== -1 && ei > si) {
      try { parsed = JSON.parse(txt.substring(si, ei + 1)); } catch(e2) {}
    }
  }
}

if (!parsed && aiOutput.qualificationRate !== undefined) {
  parsed = aiOutput;
}

if (!parsed && typeof aiOutput.text === 'string') {
  try {
    parsed = JSON.parse(aiOutput.text);
  } catch(e) {
    const txt = aiOutput.text;
    const si = txt.indexOf('{');
    const ei = txt.lastIndexOf('}');
    if (si !== -1 && ei > si) {
      try { parsed = JSON.parse(txt.substring(si, ei + 1)); } catch(e2) {}
    }
  }
}

// Fallback jika parsing total gagal
if (!parsed || parsed.qualificationRate === undefined) {
  parsed = {
    qualificationRate: 0,
    positionApplied: formData['Position Applied'] || 'Unknown',
    experienceLevel: 'UNKNOWN',
    yearsOfExperience: 0,
    fieldRelevance: 'UNKNOWN',
    scoreCeiling: 10,
    rawScore: 0,
    category: 'ERROR',
    explanation: 'AI output parsing failed. Please retry.',
    keyFindings: 'ERROR: Could not parse AI evaluation output.'
  };
}

// ============ EXTRACT & NORMALIZE ============
let rating = Number(parsed.qualificationRate || 0);
const fieldRelevance = (parsed.fieldRelevance || 'UNKNOWN').toUpperCase();
const positionApplied = parsed.positionApplied || formData['Position Applied'] || 'Unknown';
const scoreCeiling = Number(parsed.scoreCeiling || 10);

// Ambil experienceLevel & yearsOfExperience dari AI output
const aiExperienceLevel = (parsed.experienceLevel || 'UNKNOWN').toUpperCase();
const aiYears = Number(parsed.yearsOfExperience);

// Normalisasi: jika AI kembalikan format pecahan 0.0-1.0 (jarang), konversi ke 0-10
if (rating > 0 && rating < 1) {
  rating = Math.round(rating * 10);
}
rating = Math.max(0, Math.min(10, Math.round(rating)));

// ============ FIELD RELEVANCE CEILING ============
// Hanya potong skor jika field kandidat tidak relevan dengan posisi
if (fieldRelevance === 'IRRELEVANT' && rating > 2) {
  rating = 2;
} else if (fieldRelevance === 'RELEVANT_ADJACENT' && rating > 6) {
  rating = 6;
}
// RELEVANT_DIRECT: tidak ada pemotongan dari sisi field relevance

// ============ EXPERIENCE LEVEL CAP ============
// Gunakan label dari AI sebagai sumber utama.
// Gunakan yearsOfExperience sebagai fallback HANYA jika label = UNKNOWN.
let experienceLevel = aiExperienceLevel;

if (experienceLevel === 'UNKNOWN' && !isNaN(aiYears) && aiYears > 0) {
  if (aiYears < 1) {
    experienceLevel = 'INSUFFICIENT';
  } else if (aiYears <= 2) {
    experienceLevel = 'JUNIOR';
  } else {
    experienceLevel = 'SENIOR';
  }
}

// Terapkan cap berdasarkan level pengalaman
if (experienceLevel === 'INSUFFICIENT') {
  // Kurang dari 1 tahun: maks 3/10
  if (rating > 3) rating = 3;
} else if (experienceLevel === 'JUNIOR') {
  // 1-2 tahun: maks 6/10
  if (rating > 6) rating = 6;
}
// SENIOR (> 2 tahun) atau UNKNOWN: tidak ada cap tambahan

// ============ FINAL CLAMP 0-10 ============
rating = Math.max(0, Math.min(10, rating));

const ratingDisplay = rating + '/10';
const yearsOfExperience = isNaN(aiYears) ? 0 : aiYears;

// ============ KATEGORI ============
let category;
if (parsed.category === 'ERROR') {
  category = 'ERROR';
} else if (rating >= 7) {
  category = 'QUALIFIED';
} else if (rating >= 4) {
  category = 'REVIEW';
} else {
  category = 'NOT_QUALIFIED';
}

// Catatan penyesuaian jika skor diubah dari output AI
let explanation = parsed.explanation || '';
const originalRating = Number(parsed.qualificationRate || 0);
if (rating !== originalRating) {
  explanation += '\n\n[SYSTEM NOTE: Score adjusted from ' + originalRating + ' to ' + rating +
    '. Applied caps: ' + fieldRelevance + ' ceiling + ' + experienceLevel + ' level cap.]';
}

return {
  json: {
    'Full Name': formData['Full Name'] || '',
    'Email': formData['Email'] || '',
    'Date of Birth': formData['Date of Birth'] || '',
    'Position Applied': positionApplied,
    'experienceLevel': experienceLevel,
    'yearsOfExperience': yearsOfExperience,
    'submittedAt': formData['submittedAt'] || new Date().toISOString(),
    'qualificationRate': rating,
    'ratingDisplay': ratingDisplay,
    'category': category,
    'fieldRelevance': fieldRelevance,
    'scoreCeiling': scoreCeiling,
    'rawScore': Number(parsed.rawScore || 0),
    'explanation': explanation,
    'keyFindings': parsed.keyFindings || ''
  }
};

// ============ PREPARE UPLOAD: Merge binary CV + folder ID ============
// This node bridges the binary data from Application Form2
// with the folder ID from the search/create folder flow.

// 1. Get folder ID from the previous node
let folderId = 'root';

if ($json.id && typeof $json.id === 'string' && !$json.files) {
  // Coming from Create Folder node - direct id
  folderId = $json.id;
} else if ($json.files && $json.files.length > 0) {
  // Coming from IF(true) - passthrough from Find Folder
  folderId = $json.files[0].id;
}

// 2. Get binary data from Application Form2
const formItem = $('Application Form3').first();
const binaryData = formItem.binary;
const binaryKey = binaryData ? Object.keys(binaryData)[0] : 'data';
const fullName = formItem.json['Full Name'] || 'Unknown';
const fileName = fullName + ' - CV - ' + new Date().toISOString().slice(0, 10) + '.pdf';

// 3. Return combined data: folder ID in json + binary CV file
return {
  json: {
    folderId: folderId,
    fileName: fileName,
    binaryKey: binaryKey
  },
  binary: binaryData
};
